use actix_web::{web, Responder};
use crate::database::models::Invoice;
use crate::utils::auth::User;

pub async fn invoice_handler(
    path: web::Path<String>,
    user: web::Extension<User>,
) -> Responder {
    let invoice_id = path.into_inner();
    let invoice = Invoice::find_by_id(invoice_id, &user.claims).await;

    match invoice {
        Some(invoice) => web::json(&invoice).into_response(),
        None => web::NotFound().into_response(),
    }
}